using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _sut = new();

    private static List<OrderItem> CreateItems(params (string Name, decimal Price, int Qty)[] entries) =>
        entries.Select(e => new OrderItem { ProductName = e.Name, Price = e.Price, Quantity = e.Qty }).ToList();

    // --- CreateOrder: happy path ---

    [TestMethod]
    public void CreateOrder_ValidInputs_ReturnsOrderWithCorrectProperties()
    {
        // Arrange
        var items = CreateItems(("Widget", 10.00m, 2), ("Gadget", 5.50m, 3));

        // Act
        var order = _sut.CreateOrder("customer-1", items);

        // Assert
        Assert.IsNotNull(order);
        Assert.IsFalse(string.IsNullOrEmpty(order.Id));
        Assert.AreEqual("customer-1", order.CustomerId);
        Assert.AreEqual(2, order.Items.Count);
        Assert.AreEqual(36.50m, order.Total); // 10*2 + 5.5*3
        Assert.IsTrue(order.CreatedAt <= DateTime.UtcNow);
    }

    [TestMethod]
    [DataRow(25.00, 4, 100.00, DisplayName = "Single item")]
    [DataRow(0.00, 5, 0.00, DisplayName = "Zero price")]
    [DataRow(9.99, 1, 9.99, DisplayName = "Fractional price")]
    public void CreateOrder_VariousInputs_CalculatesCorrectTotal(double price, int qty, double expectedTotal)
    {
        var items = CreateItems(("Item", (decimal)price, qty));

        var order = _sut.CreateOrder("c1", items);

        Assert.AreEqual((decimal)expectedTotal, order.Total);
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_SumsAllItemTotals()
    {
        var items = CreateItems(("A", 10m, 1), ("B", 20m, 2), ("C", 5m, 3));

        var order = _sut.CreateOrder("c1", items);

        Assert.AreEqual(65m, order.Total); // 10 + 40 + 15
    }

    [TestMethod]
    public void CreateOrder_GeneratesUniqueIds()
    {
        var items = CreateItems(("A", 1m, 1));

        var order1 = _sut.CreateOrder("c1", items);
        var order2 = _sut.CreateOrder("c1", items);

        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    // --- CreateOrder: error cases ---

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 10m, 1));

        Assert.ThrowsException<ArgumentNullException>(() => _sut.CreateOrder(null!, items));
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() => _sut.CreateOrder("c1", null!));
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsException<InvalidOperationException>(
            () => _sut.CreateOrder("c1", []));

        Assert.AreEqual("Cannot create an order with no items.", ex.Message);
    }

    // --- GetOrder ---

    [TestMethod]
    public void GetOrder_ExistingId_ReturnsMatchingOrder()
    {
        var items = CreateItems(("Widget", 10m, 1));
        var created = _sut.CreateOrder("c1", items);

        var retrieved = _sut.GetOrder(created.Id);

        Assert.AreSame(created, retrieved);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        Assert.IsNull(_sut.GetOrder("does-not-exist"));
    }

    // --- GetOrdersByCustomer ---

    [TestMethod]
    public void GetOrdersByCustomer_MultipleOrders_ReturnsOnlyMatchingCustomer()
    {
        var items = CreateItems(("A", 1m, 1));
        _sut.CreateOrder("c1", items);
        _sut.CreateOrder("c1", items);
        _sut.CreateOrder("c2", items);

        var result = _sut.GetOrdersByCustomer("c1");

        Assert.AreEqual(2, result.Count);
        Assert.IsTrue(result.All(o => o.CustomerId == "c1"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoMatchingOrders_ReturnsEmptyList()
    {
        var result = _sut.GetOrdersByCustomer("unknown");

        Assert.AreEqual(0, result.Count);
    }
}

